param([string]$Objective="ENGREMIAT_CONTROLLED_ACTION_EXAMPLE_000",[string]$Action="NOOP_PREVIEW",[string]$Decision="DEFER",[bool]$HumanConfirmation=$false,[bool]$ExecutionAllowed=$false,[string]$OutDir="data/controlled-action-template-017/dispatcher-preview");$ErrorActionPreference="Stop";New-Item -ItemType Directory -Force -Path $OutDir|Out-Null;$approved=($Decision -eq "APPROVE" -and $HumanConfirmation -eq $true -and $ExecutionAllowed -eq $true);$apply=$false;$ts=(Get-Date).ToString("o");$result=[ordered]@{objective=$Objective;requested_action=$Action;created_at=$ts;decision=$Decision;human_confirmation=$HumanConfirmation;execution_allowed=$ExecutionAllowed;gate=if($approved){"APPROVE"}else{"DEFER"};approved=$approved;apply_executed=$apply;auto_apply=$false;remote_execution=$false;git_write=$false;status=if($approved){"APPROVED_BUT_NO_AUTO_APPLY"}else{"BLOCKED_BY_GATE"};receipt_required=$true;postcheck_required=$true};$out=Join-Path $OutDir "controlled-action-dispatcher-preview.json";$result|ConvertTo-Json -Depth 20|Set-Content $out -Encoding UTF8;Write-Host ("OK dispatcher=Invoke-ControlledActionTemplate objective="+$Objective+" status="+$result.status+" gate="+$result.gate+" apply_executed=False")
